#include <stdio.h>
#include <stdlib.h>

void** allocate_2d_matrix(size_t rows, size_t cols, size_t element_size) {
    void **array = (void **)malloc(rows * sizeof(void *));
    for(size_t i=0; i<rows; ++i){
        array[i] = malloc(cols * element_size);
    }
    return array;
}

